import { useEffect, useState, useContext } from "react";
import { useNavigate } from "react-router-dom";
import {
  getVoterElection,
  applyAsCandidate
} from "../../api/electionsApi";
import { AuthContext } from "../../context/AuthContext";

function Elections() {
  const { user } = useContext(AuthContext);
  const [election, setElection] = useState(null);
  const [manifesto, setManifesto] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    getVoterElection()
      .then(res => setElection(res.data))
      .catch(err => console.error(err));
  }, []);

  const apply = async () => {
    if (!manifesto.trim()) {
      alert("Please enter your manifesto");
      return;
    }

    try {
      await applyAsCandidate({
        election_id: election.id,
        manifesto
      });

      alert("Nomination submitted successfully");
      setManifesto("");
    } catch (err) {
      alert(err.response?.data?.msg || "Failed to apply");
    }
  };

  if (!election || !election.id) {
    return <p>No election available</p>;
  }

  return (
    <div>
      <h2>Election</h2>

      <p>
        Status: <b>{election.status}</b>
      </p>

      {/* ==========================
          Candidate Application
         ========================== */}
      {election.status === "NOMINATION_OPEN" && (
        <div style={{ marginTop: "20px" }}>
          <h3>Apply as Candidate</h3>

          <textarea
            placeholder="Enter your manifesto"
            rows={5}
            cols={50}
            value={manifesto}
            onChange={e => setManifesto(e.target.value)}
          />

          <br /><br />

          <button onClick={apply}>
            Submit Nomination
          </button>
        </div>
      )}

      {/* ==========================
          Voting Section
         ========================== */}
      {election.status === "ONGOING" ? (
        <button onClick={() => navigate("/voter/vote")}>
          Vote Now
        </button>
      ) : election.status !== "NOMINATION_OPEN" ? (
        <p>Voting is not open yet</p>
      ) : null}
    </div>
  );
}

export default Elections;
